51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_MINIMUM = 5;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_MINIMUM_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	const BASE_PREMIUMS: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const COMPONENT_BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const countByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const groupBasePremium = ([type, count]: [string, number]): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const sumBy = <T>(values: T[], amount: (value: T) => number): number =>
86	  values.reduce((total, value) => total + amount(value), 0);
87	
88	const assertKnownItemTypes = (items: Item[]): void => {
89	  for (const item of items) {
90	    if (!(item.type in BASE_PREMIUMS)) {
91	      throw new Error(`Unknown item type: ${item.type}`);
92	    }
93	  }
94	};
95	
96	const computeBasePremium = (items: Item[]): number =>
97	  sumBy([...countByType(items)], groupBasePremium);
98	
99	const itemCurseSurcharge = (item: Item): number =>
100	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
101	
102	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
103	
104	const itemHighEnchantmentSurcharge = (item: Item): number =>
105	  enchantmentOf(item) >= HIGH_ENCHANTMENT_MINIMUM
106	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
107	    : 0;
108	
109	const quotePremium = (
110	  customer: Customer,
111	  items: Item[],
112	  isFollowUp: boolean,
113	): number => {
114	  const basePremium = computeBasePremium(items);
115	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
116	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
117	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
118	  const loyaltyDiscount =
119	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
120	      ? basePremium * LOYALTY_DISCOUNT_RATE
121	      : 0;
122	  const followUpDiscount = isFollowUp
123	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
124	    : 0;
125	  const unroundedPremium =
126	    basePremium +
127	    curseSurcharge +
128	    highEnchantmentSurcharge +
129	    firstInsuranceSurcharge -
130	    loyaltyDiscount -
131	    followUpDiscount +
132	    PROCESSING_FEE;
133	  return Math.ceil(unroundedPremium);
134	};
135	
136	const DEDUCTIBLE = 100;
137	const PAYOUT_CAP_MULTIPLIER = 2;
138	const HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT = 8;
139	const HALF_REIMBURSEMENT_RATE = 0.5;
140	
141	const INSURANCE_VALUES: Record<string, number> = {
142	  sword: 1000,
143	  amulet: 600,
144	  rune: 250,
145	};
146	
147	const insuranceValueOf = (item: Item): number => INSURANCE_VALUES[item.type];
148	
149	const reimbursementFor = (insuredItem: Item, damage: Damage): number =>
150	  enchantmentOf(insuredItem) >= HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT
151	    ? damage.amount * HALF_REIMBURSEMENT_RATE
152	    : damage.amount;
153	
154	const findInsuredItem = (insuredItems: Item[], damage: Damage): Item =>
155	  insuredItems.find((item) => item.type === damage.itemType) as Item;
156	
157	const damagePayout = (insuredItems: Item[], damage: Damage): number =>
158	  reimbursementFor(findInsuredItem(insuredItems, damage), damage) - DEDUCTIBLE;
159	
160	const settleClaim = (
161	  insuredItems: Item[],
162	  damages: Damage[],
163	  remainingCap: number,
164	): ClaimResult => {
165	  const uncappedPayout = sumBy(damages, (damage) =>
166	    damagePayout(insuredItems, damage),
167	  );
168	  const unroundedPayout = Math.min(uncappedPayout, remainingCap);
169	  const payout = Math.floor(unroundedPayout);
170	  return { payout, remainingCap: remainingCap - payout };
171	};
172	
173	const policyOf = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
174	  scenario.steps[claim.policy] as QuoteStep;
175	
176	const initialCapOf = (policy: QuoteStep): number =>
177	  PAYOUT_CAP_MULTIPLIER * sumBy(policy.items, insuranceValueOf);
178	
179	export const processScenario = (scenario: Scenario): { results: Result[] } => {
180	  const remainingCaps = new Map<number, number>();
181	  return {
182	    results: scenario.steps.map((step, index) => {
183	      if (step.op === "quote") {
184	        assertKnownItemTypes(step.items);
185	        return { premium: quotePremium(scenario.customer, step.items, index > 0) };
186	      }
187	      const policy = policyOf(scenario, step);
188	      const remainingCap =
189	        remainingCaps.get(step.policy) ?? initialCapOf(policy);
190	      const result = settleClaim(
191	        policy.items,
192	        step.incident.damages,
193	        remainingCap,
194	      );
195	      remainingCaps.set(step.policy, result.remainingCap);
196	      return result;
197	    }),
198	  };
199	};
